import org.flowable.bpmn.model.Process;
import org.openmetadata.schema.governance.workflows.WorkflowConfiguration;
import org.openmetadata.schema.governance.workflows.elements.nodes.startEvent.StartEventDefinition;
import org.openmetadata.service.governance.workflows.elements.NodeInterface;
import org.openmetadata.service.governance.workflows.flowable.builders.StartEventBuilder;

public class StartEvent implements NodeInterface {
  private final org.flowable.bpmn.model.StartEvent startEvent;

  public StartEvent(StartEventDefinition nodeDefinition, WorkflowConfiguration config) {
    this.startEvent = new StartEventBuilder().id(nodeDefinition.getName()).build();
    attachWorkflowInstanceExecutionIdSetterListener(startEvent);

    if (config.getStoreStageStatus()) {
      attachWorkflowInstanceStageListeners(startEvent);
    }
  }

  public void addToWorkflow(BpmnModel model, Process process) {
    process.addFlowElement(startEvent);
  }
}

package org.openmetadata.service.governance.workflows.flowable.builders;

import org.flowable.bpmn.model.CallActivity;

public class CallActivityBuilder extends FlowableElementBuilder<CallActivityBuilder> {
  private String calledElement;
  private boolean inheritBusinessKey;
  private boolean inheritVariables;

  public CallActivityBuilder calledElement(String calledElement) {
    this.calledElement = calledElement;
    return this;
  }

  public CallActivityBuilder inheritBusinessKey(boolean inheritBusinessKey) {
    this.inheritBusinessKey = inheritBusinessKey;
    return this;
  }

  public CallActivityBuilder inheritVariables(boolean inheritVariables) {
    this.inheritVariables = inheritVariables;
    return this;
  }

  @Override
  public CallActivity build() {
    CallActivity callActivity = new CallActivity();
    callActivity.setId(id);
    callActivity.setName(id);
    callActivity.setCalledElement(calledElement);
    callActivity.setInheritBusinessKey(inheritBusinessKey);
    callActivity.setInheritVariables(inheritVariables);
    return callActivity;
  }
}

package org.openmetadata.service.governance.workflows.flowable.builders;

import org.flowable.bpmn.model.ExclusiveGateway;

public class ExclusiveGatewayBuilder extends FlowableElementBuilder<ExclusiveGatewayBuilder> {

  private boolean async = true;
  private boolean exclusive = true;
  private String name;

  public ExclusiveGatewayBuilder setAsync(boolean async) {
    this.async = async;
    return this;
  }

  public ExclusiveGatewayBuilder exclusive(boolean exclusive) {
    this.exclusive = exclusive;
    return this;
  }

  public ExclusiveGatewayBuilder name(String name) {
    this.name = name;
    return this;
  }

  @Override
  public ExclusiveGateway build() {
    ExclusiveGateway gateway = new ExclusiveGateway();
    gateway.setId(id);
    gateway.setName(name);
    gateway.setAsynchronous(async);
    gateway.setExclusive(exclusive);
    return gateway;
  }
}

package org.openmetadata.service.clients.pipeline.config.types;

import org.openmetadata.schema.entity.services.ingestionPipelines.IngestionPipeline;
import org.openmetadata.schema.metadataIngestion.ApplicationPipeline;
import org.openmetadata.schema.metadataIngestion.OpenMetadataAppConfig;
import org.openmetadata.schema.utils.JsonUtils;

public class ApplicationWorkflowConfig {
  public OpenMetadataAppConfig buildOMApplicationConfig(IngestionPipeline ingestionPipeline) {

    ApplicationPipeline externalApplicationConfig =
        JsonUtils.convertValue(
            ingestionPipeline.getSourceConfig().getConfig(), ApplicationPipeline.class);

    return new OpenMetadataAppConfig()
        .withSourcePythonClass(externalApplicationConfig.getSourcePythonClass())
        .withAppConfig(externalApplicationConfig.getAppConfig())
        .withAppPrivateConfig(externalApplicationConfig.getAppPrivateConfig());
  }
}

package org.openmetadata.service.exception;

import lombok.Getter;

@Getter
public class VectorDimensionException extends Exception {
  private final String currentModel;
  private final int currentDimension;
  private final String requiredModel;
  private final int requiredDimension;

  public VectorDimensionException(
      String message,
      String currentModel,
      int currentDimension,
      String requiredModel,
      int requiredDimension) {
    super(message);
    this.currentModel = currentModel;
    this.currentDimension = currentDimension;
    this.requiredModel = requiredModel;
    this.requiredDimension = requiredDimension;
  }

  public boolean isModelMismatch() {
    return currentModel != null && requiredModel != null && !currentModel.equals(requiredModel);
  }

  public boolean isDimensionMismatch() {
    return currentDimension != requiredDimension;
  }
}

package com.alibaba.otter.canal.instance.spring.support;

import java.beans.PropertyEditorSupport;
import java.net.InetSocketAddress;

import org.springframework.beans.PropertyEditorRegistrar;
import org.springframework.beans.PropertyEditorRegistry;

import com.alibaba.otter.canal.common.utils.AddressUtils;

public class SocketAddressEditor extends PropertyEditorSupport implements PropertyEditorRegistrar {

    public void registerCustomEditors(PropertyEditorRegistry registry) {
        registry.registerCustomEditor(InetSocketAddress.class, this);
    }

    public void setAsText(String text) throws IllegalArgumentException {
        String[] addresses = AddressUtils.splitIPAndPort(text);
        if (addresses.length > 0) {
            if (addresses.length != 2) {
                throw new RuntimeException("address[" + text + "] is illegal, eg.127.0.0.1:3306");
            } else {
                setValue(new InetSocketAddress(addresses[0], Integer.valueOf(addresses[1])));
            }
        } else {
            setValue(null);
        }
    }
}
